#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define MAX_N 100
#define MAX_MAGICAL_POWER 1000000000

struct Chef {
    int cookingPower;
    int magicalPower;
};

int compareChefs(const void *a, const void *b) {
    struct Chef *chefA = (struct Chef *)a;
    struct Chef *chefB = (struct Chef *)b;
    double ratioA = (double)chefA->cookingPower / chefA->magicalPower;
    double ratioB = (double)chefB->cookingPower / chefB->magicalPower;
    if (ratioA < ratioB) return -1;
    if (ratioA > ratioB) return 1;
    return 0;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N, X;
        scanf("%d %d", &N, &X);
        struct Chef chefs[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &chefs[i].cookingPower, &chefs[i].magicalPower);
        }
        qsort(chefs, N, sizeof(struct Chef), compareChefs);
        int totalEffort = 0;
        int totalMagicalPower = 0;
        for (int i = 0; i < N; i++) {
            if (totalMagicalPower >= X) {
                chefs[i].cookingPower /= 3;
                chefs[i].magicalPower /= 3;
                totalMagicalPower -= X;
            }
            totalEffort += chefs[i].cookingPower;
            totalMagicalPower += chefs[i].magicalPower;
            if (totalMagicalPower >= 666) break;
        }
        if (totalMagicalPower >= 666) {
            printf("%d\n", (int)round(totalEffort));
        } else {
            printf("impossible\n");
        }
    }
    return 0;
}

