import java.util.Arrays;
import java.util.Scanner;

public class Main {
    static class Chef implements Comparable<Chef> {
        int cookingPower;
        int magicalPower;
        Chef(int cookingPower, int magicalPower) {
            this.cookingPower = cookingPower;
            this.magicalPower = magicalPower;
        }
        @Override
        public int compareTo(Chef other) {
            return Double.compare((double)cookingPower / magicalPower, (double)other.cookingPower / other.magicalPower);
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int N = scanner.nextInt();
            int X = scanner.nextInt();
            Chef[] chefs = new Chef[N];
            for (int i = 0; i < N; i++) {
                chefs[i] = new Chef(scanner.nextInt(), scanner.nextInt());
            }
            Arrays.sort(chefs);
            int totalEffort = 0;
            int totalMagicalPower = 0;
            for (int i = 0; i < N; i++) {
                if (totalMagicalPower >= X) {
                    chefs[i].cookingPower /= 3;
                    chefs[i].magicalPower /= 3;
                    totalMagicalPower -= X;
                }
                totalEffort += chefs[i].cookingPower;
                totalMagicalPower += chefs[i].magicalPower;
                if (totalMagicalPower >= 666) break;
            }
            if (totalMagicalPower >= 666) {
                System.out.println((int)Math.round(totalEffort));
            } else {
                System.out.println("impossible");
            }
        }
    }
}

